//! Tier-C "interpreter-embed" packager — GG topology + the prebuilt
//! `gg-walker-wasm` runtime (Betti → WASM Phase 5 Tier C).
//!
//! # Artifact contract
//!
//! Unlike Tier A (`aot_wasm.rs`), which compiles each certified topology to
//! bespoke wasm, Tier C ships ONE program-independent wasm interpreter (the
//! `gg-walker-wasm` cdylib, json-v1 ABI, zero imports) and moves the program
//! into the **input envelope** (see the walker crate docs for the normative
//! v1/v2/v3 envelope contract — v1 `{topology, input}`, v2 `+ helpers`, v3
//! `+ optional budget/cursor` for bounded/resumable walks):
//!
//! ```json
//! { "topology": { ...GgTopology JSON... }, "input": <program input> }
//! ```
//!
//! or, when the export's certified call graph reaches other extracted
//! functions in the same scan (source-borne programs like `echo.ts`):
//!
//! ```json
//! { "topology": { ... }, "helpers": { "<fn>": { ...GgTopology... } }, "input": <program input> }
//! ```
//!
//! Consequences, spelled out:
//!
//! - `emit_gg_embed_for_export` output bytes = **walker bytes + a
//!   `gnosis-betti-manifest` custom section** whose `topologyHash` pins the
//!   topology. The topology itself is NOT inside the module (a cdylib cannot
//!   read its own custom sections; data-segment splicing of a
//!   `gnosis-gg-topology` section is documented future work in the walker
//!   crate docs).
//! - A sidecar `<artifactId>.topology.json` is emitted next to the module
//!   (see [`prepare_gg_embed_artifacts`]) so hosts can construct the
//!   envelope; verify it against `manifest.topologyHash`
//!   ([`gg_embed_topology_hash`]) before trusting it. **Sidecar shape is
//!   versioned by construction**: a helper-free export keeps the bare
//!   `GgTopology` JSON (byte-identical to the pre-helpers contract, so
//!   existing hashes do not churn); an export with helpers emits the
//!   program wrapper `{"topology": …, "helpers": {…}}` — exactly those two
//!   keys, which no bare `GgTopology` serialization can collide with. Hosts
//!   splice `input` in to form the envelope (bare sidecar → **envelope v1**
//!   `{"topology", "input"}`; helper-wrapper sidecar → **envelope v2**
//!   `{"topology", "helpers", "input"}`). NB "v2" here is the ENVELOPE version;
//!   the sidecar wrapper `{"topology","helpers"}` is the pre-input MATERIAL, not
//!   an envelope by itself.
//! - Manifest: `tier: "interpreter-embed"`, `certified_class: "gg-embed"`,
//!   `abi: "json-v1"`, `imports: []`, `decline_semantics: "trap"` — the
//!   walker is built with `panic = "abort"`, so every uncertified shape is a
//!   real `unreachable` trap and hosts fall back to the interpreter.
//!
//! # Admission (fail closed)
//!
//! Coverage is enforced twice:
//!
//! 1. **Package time**: the walker rlib runs natively here —
//!    `gg_walker_wasm::validate_program_json` performs the walker's own
//!    static admission sweep over the FULL program (labels, edge types,
//!    certified callees, foil fork/fold shape, `expr`/`args` IR forms,
//!    helper arity, call-graph acyclicity). Topologies outside the
//!    property-carried subset never become artifacts. A runtime probe with a
//!    synthetic input is deliberately NOT attempted — the certified inputs
//!    are program-specific, so a generic probe cannot prove anything the
//!    static sweep does not already check.
//! 2. **Run time**: input-dependent shapes (missing/non-string `userId`,
//!    unbound identifiers, missing input fields, non-string template parts)
//!    trap inside the wasm.
//!
//! # Building the walker
//!
//! The packager requires the PREBUILT walker binary — it never shells out to
//! cargo. Build it once per toolchain bump:
//!
//! ```text
//! cd open-source/gnosis/polyglot/gg-walker-wasm
//! cargo build --target wasm32-unknown-unknown --release
//! ```
//!
//! Override the location with `GG_WALKER_WASM_PATH`.

use std::collections::BTreeMap;
use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{bail, Context, Result};

use crate::aot_c::fnv1a64;
use crate::aot_wasm::{
    append_manifest_section, sha256_hex, BettiWasmLimits, BettiWasmManifest,
    BETTI_WASM_ARTIFACT_VERSION,
};
use crate::gg_compiler::GgTopology;
use crate::serialization::PolyglotOrchestrationResult;

/// Env override for the prebuilt walker wasm binary.
pub const GG_WALKER_WASM_PATH_ENV: &str = "GG_WALKER_WASM_PATH";

/// Advisory memory ceiling recorded in the manifest. The walker's memory is
/// growable (Rust std allocator); topologies and inputs in the certified
/// subset are tiny, so 256 pages (16 MiB) is a generous host-side cap.
const GG_EMBED_MEMORY_PAGES_MAX: u32 = 256;

#[derive(Debug, Clone)]
pub struct EmittedGgEmbed {
    /// Walker module bytes + trailing `gnosis-betti-manifest` custom section.
    pub bytes: Vec<u8>,
    pub manifest: BettiWasmManifest,
    /// The exact sidecar JSON pinned by `manifest.topology_hash` — a bare
    /// `GgTopology` (helper-free export) or the program wrapper
    /// `{"topology": …, "helpers": {…}}`. Hosts splice the program input in:
    /// `{"topology": …, "input": …}` respectively
    /// `{"topology": …, "helpers": …, "input": …}` (json-v1 envelope).
    pub topology_json: String,
}

impl EmittedGgEmbed {
    pub fn manifest_json(&self) -> String {
        serde_json::to_string_pretty(&self.manifest)
            .expect("betti-wasm manifest serializes infallibly")
    }
}

/// Where the prebuilt walker binary is expected: `GG_WALKER_WASM_PATH`, else
/// the walker crate's own release target directory (source-checkout layout).
pub fn walker_wasm_path() -> PathBuf {
    if let Ok(value) = std::env::var(GG_WALKER_WASM_PATH_ENV) {
        return PathBuf::from(value);
    }
    Path::new(env!("CARGO_MANIFEST_DIR"))
        .join("gg-walker-wasm")
        .join("target")
        .join("wasm32-unknown-unknown")
        .join("release")
        .join("gg_walker_wasm.wasm")
}

fn load_walker_bytes() -> Result<Vec<u8>> {
    let path = walker_wasm_path();
    if !path.exists() {
        bail!(
            "gg-walker-wasm binary not found at {} — build gg-walker-wasm first:\n  \
             cd open-source/gnosis/polyglot/gg-walker-wasm && \
             cargo build --target wasm32-unknown-unknown --release\n\
             (or point {GG_WALKER_WASM_PATH_ENV} at a prebuilt walker)",
            path.display()
        );
    }
    fs::read(&path).with_context(|| format!("failed to read walker wasm {}", path.display()))
}

/// Callee names the walker's user-call machinery never resolves against
/// helpers: the certified builtins.
const BUILTIN_CALLEES: [&str; 2] = ["Promise.all", "merge"];

/// Every `callee` property in `topology` that is not a certified builtin —
/// the candidate user-defined helper names.
fn user_callees(topology: &GgTopology) -> Vec<String> {
    topology
        .nodes
        .iter()
        .filter_map(|node| node.properties.get("callee"))
        .filter(|callee| !BUILTIN_CALLEES.contains(&callee.as_str()))
        .cloned()
        .collect()
}

/// Collect the helper topologies the export's call graph can reach:
/// every non-builtin `callee` that names another topology in the SAME scan
/// is included, transitively. Callees with no matching topology are simply
/// left out — the walker's static admission then declines the program,
/// which is the fail-closed intent (never guess at a callee's semantics).
fn collect_gg_embed_helpers<'a>(
    scan: &'a PolyglotOrchestrationResult,
    root: &GgTopology,
) -> BTreeMap<&'a str, &'a GgTopology> {
    let mut helpers: BTreeMap<&'a str, &'a GgTopology> = BTreeMap::new();
    let mut queue = user_callees(root);
    while let Some(name) = queue.pop() {
        if helpers.contains_key(name.as_str()) {
            continue;
        }
        let Some(found) = scan
            .scan_result
            .topologies
            .iter()
            .find(|topology| topology.function_name == name)
        else {
            continue;
        };
        helpers.insert(found.function_name.as_str(), &found.topology);
        queue.extend(user_callees(&found.topology));
    }
    helpers
}

/// Public envelope-material accessor for `export_name`: the sidecar JSON
/// (bare `GgTopology`, or the `{"topology","helpers"}` helper wrapper — the
/// pre-`input` material for an envelope v1 / v2 respectively) WITHOUT
/// packaging the walker binary — the walker-free lane hosted compile
/// services use (`gnexec --emit-gg-envelope`) to obtain the material a
/// betti-station executes from its bundled walker.
pub fn gg_embed_sidecar_json_for_export(
    scan: &PolyglotOrchestrationResult,
    export_name: &str,
) -> Result<String> {
    let entry = scan
        .scan_result
        .topologies
        .iter()
        .find(|topology| topology.function_name == export_name)
        .with_context(|| format!("export '{export_name}' not found"))?;
    gg_embed_sidecar_json(scan, &entry.topology)
}

/// Build the sidecar text for an export: bare `GgTopology` JSON when its
/// call graph needs no helpers (byte-identical to the pre-helpers contract),
/// else the program wrapper `{"topology": …, "helpers": {…}}`. Both shapes
/// serialize with sorted keys (serde_json's default `Map` is a BTreeMap), so
/// the sidecar — and therefore `topologyHash` — is deterministic.
fn gg_embed_sidecar_json(
    scan: &PolyglotOrchestrationResult,
    root: &GgTopology,
) -> Result<String> {
    let helpers = collect_gg_embed_helpers(scan, root);
    if helpers.is_empty() {
        return serde_json::to_string(root).context("serialize gg-embed topology");
    }
    let mut helpers_map = serde_json::Map::new();
    for (name, topology) in helpers {
        helpers_map.insert(
            name.to_string(),
            serde_json::to_value(topology).context("serialize gg-embed helper topology")?,
        );
    }
    let wrapper = serde_json::json!({
        "topology": serde_json::to_value(root).context("serialize gg-embed topology")?,
        "helpers": helpers_map,
    });
    serde_json::to_string(&wrapper).context("serialize gg-embed program sidecar")
}

/// The `topologyHash` recipe for gg-embed artifacts: fnv1a64 over the tagged
/// sidecar bytes. Hosts re-derive this from `<artifactId>.topology.json` to
/// verify the envelope they are about to feed the walker.
pub fn gg_embed_topology_hash(topology_json: &str) -> String {
    let mut bytes = Vec::with_capacity(topology_json.len() + 32);
    bytes.extend_from_slice(b"monster-gg-embed-topology-v1\0");
    bytes.extend_from_slice(topology_json.as_bytes());
    format!("{:016x}", fnv1a64(&bytes))
}

fn fingerprint_gg_embed(
    scan: &PolyglotOrchestrationResult,
    source: &str,
    export_name: &str,
    walker_bytes: &[u8],
    topology_json: &str,
) -> String {
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"monster-gg-embed-v1\0");
    bytes.extend_from_slice(export_name.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(scan.scan_result.file_path.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(scan.scan_result.language.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(source.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(walker_bytes);
    bytes.push(0);
    bytes.extend_from_slice(topology_json.as_bytes());
    format!("{:016x}", fnv1a64(&bytes))
}

/// Package `export_name`'s GG topology as a Tier-C interpreter-embed
/// artifact. Fails closed when the topology is outside the walker's
/// certified property-carried subset, or when the prebuilt walker binary is
/// missing.
pub fn emit_gg_embed_for_export(
    scan: &PolyglotOrchestrationResult,
    source: &str,
    export_name: &str,
) -> Result<EmittedGgEmbed> {
    let entry = scan
        .scan_result
        .topologies
        .iter()
        .find(|topology| topology.function_name == export_name)
        .with_context(|| format!("export '{export_name}' not found"))?;

    let topology_json = gg_embed_sidecar_json(scan, &entry.topology)?;

    // Package-time admission: the walker's own static sweep over the full
    // program (root + helpers), run natively.
    if let Err(decline) = gg_walker_wasm::validate_program_json(&topology_json) {
        bail!(
            "topology '{export_name}' is outside the gg-walker property-carried subset \
             (would trap at runtime): {decline}"
        );
    }

    let core = load_walker_bytes()?;
    let sha256 = sha256_hex(&core);
    let byte_length = core.len() as u64;
    let artifact_id = fingerprint_gg_embed(scan, source, export_name, &core, &topology_json);
    let topology_hash = gg_embed_topology_hash(&topology_json);
    let source_hash = format!("{:016x}", fnv1a64(source.as_bytes()));

    let manifest = BettiWasmManifest {
        artifact_version: BETTI_WASM_ARTIFACT_VERSION,
        artifact_id,
        topology_hash,
        source_hash,
        language: scan.scan_result.language.clone(),
        file_path: scan.scan_result.file_path.clone(),
        function_name: export_name.to_string(),
        certified_class: "gg-embed",
        tier: "interpreter-embed",
        imports: Vec::new(),
        pure: true,
        limits: BettiWasmLimits {
            memory_pages_max: GG_EMBED_MEMORY_PAGES_MAX,
            // No wasm fuel global: the walker bounds itself with a hop
            // budget and the certified subset is loop-free.
            fuel: None,
        },
        byte_length,
        sha256,
        decline_semantics: "trap",
        wasm_opt: false,
        export_name: "main",
        abi: "json-v1",
        memory_export: "memory",
        alloc_export: "gnosis_alloc",
        result_length_export: "gnosis_result_len",
        free_export: "gnosis_free",
    };

    let manifest_json =
        serde_json::to_vec(&manifest).context("serialize gg-embed betti-wasm manifest")?;
    let bytes = append_manifest_section(core, &manifest_json);

    Ok(EmittedGgEmbed {
        bytes,
        manifest,
        topology_json,
    })
}

// ── Tier-C admission report (Wave A3: one admission definition shared
//    between the Rust walker/packager and the TS edge runtime) ─────────

/// The shared Tier-C admission verdict. This is a THIN wrapper over the
/// walker rlib's `validate_program` — no second admission logic lives here.
/// The TS side (`open-source/x-gnosis/src/gg-admission.ts`) ports the SAME
/// static checks with a comment-mapped 1:1 correspondence and fixture-tests
/// verdict parity by driving THIS definition through
/// `gnexec --print-gg-admission`.
#[derive(Debug, Clone, serde::Serialize)]
pub struct AdmissionReport {
    /// True when the export's full program (root topology + the helper
    /// topologies its certified call graph reaches) sits inside the
    /// walker's certified property-carried subset.
    pub admitted: bool,
    /// Decline reasons. The walker's `validate_program` is FAIL-FAST, so
    /// this carries at most one entry; empty exactly when `admitted`.
    pub reasons: Vec<String>,
}

/// Tier-C admission report for `export_name` in `scan` — the same
/// package-time gate `emit_gg_embed_for_export` enforces, reported instead
/// of bailed. Does NOT require the prebuilt walker binary (static admission
/// runs on the walker rlib natively).
pub fn tier_c_admission_report(
    scan: &PolyglotOrchestrationResult,
    export_name: &str,
) -> AdmissionReport {
    let Some(entry) = scan
        .scan_result
        .topologies
        .iter()
        .find(|topology| topology.function_name == export_name)
    else {
        return AdmissionReport {
            admitted: false,
            reasons: vec![format!("export '{export_name}' not found in scan")],
        };
    };
    match gg_embed_sidecar_json(scan, &entry.topology) {
        Ok(topology_json) => tier_c_admission_report_for_sidecar(&topology_json),
        Err(error) => AdmissionReport {
            admitted: false,
            reasons: vec![format!("sidecar serialization failed: {error}")],
        },
    }
}

/// Tier-C admission report over sidecar text directly — a bare `GgTopology`
/// JSON, or the program wrapper `{"topology": …, "helpers": {…}}` (the pre-`input`
/// material for an envelope v1 / v2 respectively).
/// This is the fixture-parity entrypoint: the TS suite feeds the walker's
/// checked-in `*.topology.json` fixtures (plus hand-made decliners) through
/// `gnexec --print-gg-admission <sidecar.json>` and asserts its own ported
/// verdict matches.
pub fn tier_c_admission_report_for_sidecar(sidecar_json: &str) -> AdmissionReport {
    match gg_walker_wasm::validate_program_json(sidecar_json) {
        Ok(()) => AdmissionReport {
            admitted: true,
            reasons: Vec::new(),
        },
        Err(decline) => AdmissionReport {
            admitted: false,
            reasons: vec![decline.to_string()],
        },
    }
}

/// True when `export_name`'s topology — together with the helper topologies
/// its call graph reaches in the same scan — sits inside the walker's
/// certified subset (static admission only; does NOT require the walker
/// binary).
pub fn supports_gg_embed_for_export(
    scan: &PolyglotOrchestrationResult,
    export_name: &str,
) -> bool {
    let Some(entry) = scan
        .scan_result
        .topologies
        .iter()
        .find(|topology| topology.function_name == export_name)
    else {
        return false;
    };
    let Ok(topology_json) = gg_embed_sidecar_json(scan, &entry.topology) else {
        return false;
    };
    gg_walker_wasm::validate_program_json(&topology_json).is_ok()
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct GgEmbedArtifactPaths {
    pub artifact_id: String,
    pub wasm_path: PathBuf,
    pub manifest_path: PathBuf,
    /// The envelope material: `<artifactId>.topology.json`.
    pub topology_path: PathBuf,
}

/// Emit and write the full artifact triple —
/// `<artifactId>.wasm` + `<artifactId>.manifest.json` +
/// `<artifactId>.topology.json` — into `out_dir`.
pub fn prepare_gg_embed_artifacts(
    scan: &PolyglotOrchestrationResult,
    source: &str,
    export_name: &str,
    out_dir: &Path,
) -> Result<GgEmbedArtifactPaths> {
    let emitted = emit_gg_embed_for_export(scan, source, export_name)?;
    let artifact_id = emitted.manifest.artifact_id.clone();
    fs::create_dir_all(out_dir)
        .with_context(|| format!("failed to create {}", out_dir.display()))?;
    let wasm_path = out_dir.join(format!("{artifact_id}.wasm"));
    let manifest_path = out_dir.join(format!("{artifact_id}.manifest.json"));
    let topology_path = out_dir.join(format!("{artifact_id}.topology.json"));
    fs::write(&wasm_path, &emitted.bytes)
        .with_context(|| format!("failed to write {}", wasm_path.display()))?;
    fs::write(&manifest_path, emitted.manifest_json())
        .with_context(|| format!("failed to write {}", manifest_path.display()))?;
    fs::write(&topology_path, &emitted.topology_json)
        .with_context(|| format!("failed to write {}", topology_path.display()))?;
    Ok(GgEmbedArtifactPaths {
        artifact_id,
        wasm_path,
        manifest_path,
        topology_path,
    })
}
